206→// ── WebSocket handler ────────────────────────────────────────────────
207→
208→pub async fn ws_handler(
209→    ws: WebSocketUpgrade,
210→    State(state): State<Arc<AppState>>,
211→) -> impl IntoResponse {
212→    ws.on_upgrade(move |socket| handle_socket(socket, state))
213→}
