221→/// WebSocket handler that accepts a broadcast sender directly (for use with server router).
222→pub async fn ws_handler_with_sender(
223→    ws: WebSocketUpgrade,
224→    tx: broadcast::Sender<String>,
225→) -> impl IntoResponse {
226→    ws.on_upgrade(move |socket| handle_socket_with_sender(socket, tx))
227→}
228→
229→async fn handle_socket_with_sender(socket: WebSocket, tx: broadcast::Sender<String>) {
230→    let (sender, receiver) = socket.split();
231→    let rx = tx.subscribe();
232→    run_socket_loop(sender, receiver, rx).await;
233→}
234→
235→/// Core WebSocket loop with ping/pong keepalive.
236→///
237→/// Combines broadcast forwarding, client message receiving, and periodic
238→/// ping/pong health checking into a single select loop. If no Pong is
239→/// received within [`PONG_TIMEOUT`] after a Ping is sent, the connection
240→/// is considered dead and the loop exits.
241→async fn run_socket_loop(
242→    mut sender: SplitSink<WebSocket, Message>,
243→    mut receiver: SplitStream<WebSocket>,
244→    mut rx: broadcast::Receiver<String>,
245→) {
246→    let mut ping_interval = tokio::time::interval(PING_INTERVAL);
247→    // The first tick completes immediately; consume it so the first real
248→    // ping fires after PING_INTERVAL has elapsed.
249→    ping_interval.tick().await;
250→
251→    let mut last_pong = Instant::now();
252→    let mut awaiting_pong = false;
253→
254→    loop {
255→        tokio::select! {
256→            // ── Periodic ping ───────────────────────────────────────
257→            _ = ping_interval.tick() => {
258→                // Check if the previous ping timed out
259→                if awaiting_pong && last_pong.elapsed() > PONG_TIMEOUT {
260→                    // Connection is dead — no pong received in time
261→                    break;
262→                }
263→                if sender.send(Message::Ping(vec![].into())).await.is_err() {
264→                    break;
265→                }
266→                awaiting_pong = true;
267→            }
268→
269→            // ── Broadcast forwarding ────────────────────────────────
270→            result = rx.recv() => {
271→                match result {
272→                    Ok(msg) => {
273→                        if sender.send(Message::Text(msg.into())).await.is_err() {
274→                            break;
275→                        }
276→                    }
277→                    Err(broadcast::error::RecvError::Closed) => break,
278→                    Err(broadcast::error::RecvError::Lagged(_)) => {
279→                        // Missed some messages; continue receiving
280→                        continue;
281→                    }
282→                }
283→            }
284→
285→            // ── Client messages (pong, close, etc.) ─────────────────
286→            msg = receiver.next() => {
287→                match msg {
288→                    Some(Ok(Message::Pong(_))) => {
289→                        last_pong = Instant::now();
290→                        awaiting_pong = false;
291→                    }
292→                    Some(Ok(Message::Close(_))) | None => break,
293→                    Some(Ok(_)) => {
294→                        // Ignore other messages from client (Text, Binary, Ping)
295→                    }
296→                    Some(Err(_)) => break,
297→                }
298→            }
299→        }
300→    }
301→
302→    // Best-effort close frame
303→    let _ = sender.send(Message::Close(None)).await;
304→}
