308→/// Serialize and broadcast a WsMessage to all connected WebSocket clients.
309→/// Returns silently even if no clients are connected.
310→pub fn broadcast_message(tx: &broadcast::Sender<String>, msg: &WsMessage) {
311→    match serde_json::to_string(msg) {
312→        Ok(json) => {
313→            let _ = tx.send(json); // Ignore error if no receivers
314→        }
315→        Err(e) => {
316→            eprintln!("[ws] Failed to serialize WsMessage: {}", e);
317→        }
318→    }
319→}
