use super::models::{SignalType, VerificationType};
use axum::{
    extract::{
        State,
        ws::{Message, WebSocket, WebSocketUpgrade},
    },
    response::IntoResponse,
};
use futures_util::{SinkExt, StreamExt, stream::SplitSink, stream::SplitStream};
use serde::{Deserialize, Serialize};
use std::sync::Arc;
use std::time::Duration;
use tokio::sync::broadcast;
use tokio::time::Instant;

use super::api::AppState;
use super::models::*;

/// How often to send WebSocket Ping frames.
const PING_INTERVAL: Duration = Duration::from_secs(30);

/// How long to wait for a Pong response before considering the connection dead.
const PONG_TIMEOUT: Duration = Duration::from_secs(60);

// ── WebSocket message types ──────────────────────────────────────────

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", content = "data")]
pub enum WsMessage {
    IssueCreated {
        issue: Issue,
    },
    IssueUpdated {
        issue: Issue,
    },
    // TODO: from_column/to_column should be IssueColumn once callers in pipeline.rs are updated
    IssueMoved {
        issue_id: i64,
        from_column: String,
        to_column: String,
        position: i32,
    },
    IssueDeleted {
        issue_id: i64,
    },
    PipelineStarted {
        run: PipelineRun,
    },
    PipelineProgress {
        run_id: i64,
        phase: i32,
        iteration: i32,
        percent: Option<u8>,
    },
    PipelineCompleted {
        run: PipelineRun,
    },
    PipelineFailed {
        run: PipelineRun,
    },
    PipelineError {
        run_id: i64,
        message: String,
    },
    PipelineBranchCreated {
        run_id: i64,
        branch_name: String,
    },
    PipelinePrCreated {
        run_id: i64,
        pr_url: String,
    },
    PipelinePhaseStarted {
        run_id: i64,
        phase_number: String,
        phase_name: String,
        wave: usize,
    },
    PipelinePhaseCompleted {
        run_id: i64,
        phase_number: String,
        success: bool,
    },
    PipelineReviewStarted {
        run_id: i64,
        phase_number: String,
    },
    PipelineReviewCompleted {
        run_id: i64,
        phase_number: String,
        passed: bool,
        findings_count: usize,
    },

    // Agent team lifecycle
    TeamCreated {
        run_id: i64,
        team_id: i64,
        strategy: ExecutionStrategy,
        isolation: IsolationStrategy,
        plan_summary: String,
        tasks: Vec<AgentTask>,
    },

    // Wave lifecycle
    WaveStarted {
        run_id: i64,
        team_id: i64,
        wave: i32,
        task_ids: Vec<i64>,
    },
    WaveCompleted {
        run_id: i64,
        team_id: i64,
        wave: i32,
        success_count: u32,
        failed_count: u32,
    },

    // Agent task lifecycle
    AgentTaskStarted {
        run_id: i64,
        task_id: i64,
        name: String,
        role: AgentRole,
        wave: i32,
    },
    AgentTaskCompleted {
        run_id: i64,
        task_id: i64,
        success: bool,
    },
    AgentTaskFailed {
        run_id: i64,
        task_id: i64,
        error: String,
    },

    // Agent streaming events
    AgentThinking {
        run_id: i64,
        task_id: i64,
        content: String,
    },
    AgentAction {
        run_id: i64,
        task_id: i64,
        action_type: String,
        summary: String,
        metadata: serde_json::Value,
    },
    AgentOutput {
        run_id: i64,
        task_id: i64,
        content: String,
    },
    AgentSignal {
        run_id: i64,
        task_id: i64,
        signal_type: SignalType,
        content: String,
    },

    // Pipeline stdout streaming (forge fallback path)
    PipelineOutput {
        run_id: i64,
        content: String,
    },

    // Merge events
    MergeStarted {
        run_id: i64,
        wave: i32,
    },
    MergeCompleted {
        run_id: i64,
        wave: i32,
        conflicts: bool,
    },
    MergeConflict {
        run_id: i64,
        wave: i32,
        files: Vec<String>,
    },

    // Verification results
    VerificationResult {
        run_id: i64,
        task_id: i64,
        verification_type: VerificationType,
        passed: bool,
        summary: String,
        screenshots: Vec<String>,
        details: serde_json::Value,
    },

    // Project lifecycle
    ProjectCreated {
        project: Project,
    },
    ProjectDeleted {
        project_id: i64,
    },
}

// ── WebSocket handler ────────────────────────────────────────────────

pub async fn ws_handler(
    ws: WebSocketUpgrade,
    State(state): State<Arc<AppState>>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, state))
}

async fn handle_socket(socket: WebSocket, state: Arc<AppState>) {
    let (sender, receiver) = socket.split();
    let rx = state.ws_tx.subscribe();
    run_socket_loop(sender, receiver, rx).await;
}

/// WebSocket handler that accepts a broadcast sender directly (for use with server router).
pub async fn ws_handler_with_sender(
    ws: WebSocketUpgrade,
    tx: broadcast::Sender<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket_with_sender(socket, tx))
}

async fn handle_socket_with_sender(socket: WebSocket, tx: broadcast::Sender<String>) {
    let (sender, receiver) = socket.split();
    let rx = tx.subscribe();
    run_socket_loop(sender, receiver, rx).await;
}

/// Core WebSocket loop with ping/pong keepalive.
///
/// Combines broadcast forwarding, client message receiving, and periodic
/// ping/pong health checking into a single select loop. If no Pong is
/// received within [`PONG_TIMEOUT`] after a Ping is sent, the connection
/// is considered dead and the loop exits.
async fn run_socket_loop(
    mut sender: SplitSink<WebSocket, Message>,
    mut receiver: SplitStream<WebSocket>,
    mut rx: broadcast::Receiver<String>,
) {
    let mut ping_interval = tokio::time::interval(PING_INTERVAL);
    // The first tick completes immediately; consume it so the first real
    // ping fires after PING_INTERVAL has elapsed.
    ping_interval.tick().await;

    let mut last_pong = Instant::now();
    let mut awaiting_pong = false;

    loop {
        tokio::select! {
            // ── Periodic ping ───────────────────────────────────────
            _ = ping_interval.tick() => {
                // Check if the previous ping timed out
                if awaiting_pong && last_pong.elapsed() > PONG_TIMEOUT {
                    // Connection is dead — no pong received in time
                    break;
                }
                if sender.send(Message::Ping(vec![].into())).await.is_err() {
                    break;
                }
                awaiting_pong = true;
            }

            // ── Broadcast forwarding ────────────────────────────────
            result = rx.recv() => {
                match result {
                    Ok(msg) => {
                        if sender.send(Message::Text(msg.into())).await.is_err() {
                            break;
                        }
                    }
                    Err(broadcast::error::RecvError::Closed) => break,
                    Err(broadcast::error::RecvError::Lagged(_)) => {
                        // Missed some messages; continue receiving
                        continue;
                    }
                }
            }

            // ── Client messages (pong, close, etc.) ─────────────────
            msg = receiver.next() => {
                match msg {
                    Some(Ok(Message::Pong(_))) => {
                        last_pong = Instant::now();
                        awaiting_pong = false;
                    }
                    Some(Ok(Message::Close(_))) | None => break,
                    Some(Ok(_)) => {
                        // Ignore other messages from client (Text, Binary, Ping)
                    }
                    Some(Err(_)) => break,
                }
            }
        }
    }

    // Best-effort close frame
    let _ = sender.send(Message::Close(None)).await;
}

// ── Broadcast helper ─────────────────────────────────────────────────

/// Serialize and broadcast a WsMessage to all connected WebSocket clients.
/// Returns silently even if no clients are connected.
pub fn broadcast_message(tx: &broadcast::Sender<String>, msg: &WsMessage) {
    match serde_json::to_string(msg) {
        Ok(json) => {
            let _ = tx.send(json); // Ignore error if no receivers
        }
        Err(e) => {
            eprintln!("[ws] Failed to serialize WsMessage: {}", e);
        }
    }
}

// ── Tests ────────────────────────────────────────────────────────────

