// ── Screenshot handler ────────────────────────────────────────────────

/// `GET /api/screenshots/*path` — serve a screenshot file from the project's `.forge/screenshots/` directory.
///
/// Path traversal is prevented by canonicalizing both the screenshots directory and the
/// resolved file path and verifying the file is within the directory.
///
/// **Response:** `200 OK` with the image bytes and appropriate `Content-Type` header.
///
/// **Errors:**
/// - `400 Bad Request` if the path escapes the screenshots directory
/// - `404 Not Found` if the file or directory does not exist
async fn serve_screenshot(
    State(state): State<SharedState>,
    Path(file_path): Path<String>,
) -> Result<impl IntoResponse, ApiError> {
    let project_path = state
        .db
        .call(|db| {
            let projects = db.list_projects()?;
            projects
                .first()
                .map(|p| p.path.clone())
                .ok_or_else(|| anyhow::anyhow!("No projects"))
        })
        .await
        .map_err(|e| ApiError::NotFound(e.to_string()))?;

    let screenshots_dir = std::path::PathBuf::from(&project_path).join(".forge/screenshots");
    let full_path = screenshots_dir.join(&file_path);

    // Verify resolved path is within screenshots directory (prevents path traversal)
    let canonical_dir = tokio::fs::canonicalize(&screenshots_dir)
        .await
        .map_err(|_| ApiError::NotFound("Screenshots directory not found".into()))?;
    let canonical_file = tokio::fs::canonicalize(&full_path)
        .await
        .map_err(|_| ApiError::NotFound(format!("Screenshot not found: {}", file_path)))?;
    if !canonical_file.starts_with(&canonical_dir) {
        return Err(ApiError::BadRequest("Invalid path".into()));
    }

    let content_type = match full_path.extension().and_then(|e| e.to_str()) {
        Some("png") => "image/png",
        Some("jpg" | "jpeg") => "image/jpeg",
        Some("gif") => "image/gif",
        Some("webp") => "image/webp",
        _ => "application/octet-stream",
    };

    let bytes = tokio::fs::read(&full_path)
        .await
        .map_err(|e| ApiError::Internal(format!("Failed to read screenshot: {}", e)))?;

    Ok((
        StatusCode::OK,
        [(axum::http::header::CONTENT_TYPE, content_type)],
        bytes,
    ))
}

