        // Fall back to simple progress JSON (from claude --print)
        if let Some(progress) = try_parse_progress(&line) {
            // Update DB with progress
            {
                let phase_count = progress.phase_count;
                let phase = progress.phase;
                let iteration = progress.iteration;
                if let Err(e) = db
                    .call(move |db| {
                        db.update_pipeline_progress(run_id, phase_count, phase, iteration)
                    })
                    .await
                {
                    broadcast_message(
                        tx,
                        &WsMessage::PipelineError {
                            run_id,
                            message: format!("Failed to update pipeline progress: {:#}", e),
                        },
                    );
                }
            }

            // Compute a rough percentage
            let percent = compute_percent(&progress);

            // Broadcast progress event
            broadcast_message(
                tx,
                &WsMessage::PipelineProgress {
                    run_id,
                    phase: progress.phase.unwrap_or(0),
                    iteration: progress.iteration.unwrap_or(0),
                    percent,
                },
            );
        } else if !line.is_empty()
            && last_output_broadcast.elapsed() >= std::time::Duration::from_millis(500)
        {
            // Try to extract content from stream-json format (claude --output-format stream-json)
            let content = if let Ok(json) = serde_json::from_str::<serde_json::Value>(&line) {
                // Extract text from assistant text events, tool use summaries, etc.
                if json.get("type").and_then(|t| t.as_str()) == Some("result") {
                    // Final result — extract the full text from result.content
                    None
                } else if let Some(text) = json.get("content_block_delta")
                    .and_then(|d| d.get("delta"))
                    .and_then(|d| d.get("text"))
                    .and_then(|t| t.as_str())
                {
                    Some(text.to_string())
                } else if let Some(text) = json.get("text").and_then(|t| t.as_str()) {
                    Some(text.to_string())
                } else if json.get("subtype").and_then(|s| s.as_str()) == Some("tool_use") {
                    json.get("tool_name")
                        .and_then(|t| t.as_str())
                        .map(|name| format!("[tool: {}]", name))
                } else {
                    None
                }
            } else {
                // Not JSON — use raw line
                Some(line)
            };
            if let Some(content) = content {
                if !content.is_empty() {
                    broadcast_message(
                        tx,
                        &WsMessage::PipelineOutput {
                            run_id,
                            content,
                        },
                    );
                    last_output_broadcast = std::time::Instant::now();
                }
            }
        }
    }

    // Wait for the process to finish — retrieve the child from the map
    let status = {
        let mut processes = running_processes.lock().await;
        if let Some(handle) = processes.remove(&run_id) {
            match handle {
                RunHandle::Process(mut child) => child
                    .wait()
                    .await
                    .context("Failed to wait for child process")?,
                RunHandle::Container(_) => {
                    anyhow::bail!("Unexpected container handle in local execution path")
                }
            }
        } else {
            // Process was already removed (e.g., cancelled)
            anyhow::bail!("Pipeline was cancelled")
        }
    };

    if status.success() {
        // Take last 500 chars as summary
        let summary = if all_output.len() > 500 {
            format!("...{}", &all_output[all_output.len() - 500..])
        } else {
            all_output
        };
        Ok(summary)
    } else {
        anyhow::bail!(
            "Pipeline process failed with exit code: {:?}",
            status.code()
        )
    }
