  1→/** Unified state hook for the Mission Control dashboard — aggregates all projects into a single view. */
  2→import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
  3→import { api } from '../api/client';
  4→import { useWsSubscribe } from '../contexts/WebSocketContext';
  5→import type {
  6→  Project,
  7→  Issue,
  8→  PipelineRun,
  9→  PipelinePhase,
 10→  AgentRunCard,
 11→  EventLogEntry,
 12→  WsMessage,
 13→  RunStatusFilter,
 14→  AgentTeamDetail,
 15→  AgentEvent,
 16→} from '../types';
 17→
 18→/** Internal state shape for the Mission Control hook */
 19→interface MissionControlState {
 20→  projects: Project[];
 21→  runs: Map<number, PipelineRun>;
 22→  issues: Map<number, Issue>;
 23→  phases: Map<number, PipelinePhase[]>;
 24→  agentTeams: Map<number, AgentTeamDetail>;
 25→  agentEvents: Map<number, AgentEvent[]>;
 26→  pipelineEvents: Map<number, AgentEvent[]>;
 27→  eventLog: EventLogEntry[];
 28→  loading: boolean;
 29→  error: string | null;
 30→}
 31→
 32→/** An idle issue card — issue without an active pipeline run */
 33→export interface IdleIssueCard {
 34→  issue: Issue;
 35→  project: Project;
 36→}
 37→
 38→/** Return type of the useMissionControl hook */
 39→export interface MissionControlReturn {
 40→  /** All loaded projects */
 41→  projects: Project[];
 42→  /** Filtered and sorted agent run cards for the grid */
 43→  agentRunCards: AgentRunCard[];
 44→  /** Issues without active pipeline runs, available to start */
 45→  idleIssueCards: IdleIssueCard[];
 46→  /** Run counts by status */
 47→  statusCounts: Record<RunStatusFilter, number>;
 48→  /** Chronological event log entries */
 49→  eventLog: EventLogEntry[];
 50→  /** Pipeline phases by run ID */
 51→  phases: Map<number, PipelinePhase[]>;
 52→  /** Agent team details by run ID */
 53→  agentTeams: Map<number, AgentTeamDetail>;
 54→  /** Agent events by task ID */
 55→  agentEvents: Map<number, AgentEvent[]>;
 56→  /** Pipeline-level output events by run ID (for forge fallback path) */
 57→  pipelineEvents: Map<number, AgentEvent[]>;
 58→  /** Whether initial data is still loading */
 59→  loading: boolean;
 60→  /** Error message from initial load, or null */
 61→  error: string | null;
 62→  /** Currently selected project ID filter, or null for all */
 63→  selectedProjectId: number | null;
 64→  /** Set the project filter */
 65→  setSelectedProjectId: (id: number | null) => void;
 66→  /** Current status filter */
 67→  statusFilter: RunStatusFilter;
 68→  /** Set the status filter */
 69→  setStatusFilter: (filter: RunStatusFilter) => void;
 70→  /** Trigger a pipeline run for an issue */
 71→  triggerPipeline: (issueId: number) => Promise<void>;
 72→  /** Cancel a running pipeline */
 73→  cancelPipeline: (runId: number) => Promise<void>;
 74→  /** Create a new issue in a project */
 75→  createIssue: (projectId: number, title: string, description: string) => Promise<Issue>;
 76→  /** Create a new project */
 77→  createProject: (name: string, path: string) => Promise<Project>;
 78→  /** Clone a project from a repository URL */
 79→  cloneProject: (repoUrl: string) => Promise<Project>;
 80→  /** Delete a project and all its data */
 81→  deleteProject: (projectId: number) => Promise<void>;
 82→  /** Refresh all data from the server */
 83→  refresh: () => Promise<void>;
 84→  /** Issue counts grouped by project ID */
 85→  issuesByProject: Map<number, number>;
 86→}
 87→
 88→/** Status sort order: running first, then queued, failed, completed, cancelled */
 89→const STATUS_ORDER: Record<string, number> = {
 90→  running: 0,
 91→  queued: 1,
 92→  failed: 2,
 93→  completed: 3,
 94→  cancelled: 4,
 95→};
 96→
 97→/**
 98→ * Primary data hook for the Mission Control dashboard.
 99→ * Aggregates data from all projects, handles WebSocket updates,
100→ * and provides filtering and actions.
101→ */
102→export default function useMissionControl(): MissionControlReturn {
103→  const [state, setState] = useState<MissionControlState>({
104→    projects: [],
105→    runs: new Map(),
106→    issues: new Map(),
107→    phases: new Map(),
108→    agentTeams: new Map(),
109→    agentEvents: new Map(),
110→    pipelineEvents: new Map(),
111→    eventLog: [],
112→    loading: true,
113→    error: null,
114→  });
115→
116→  const [selectedProjectId, setSelectedProjectId] = useState<number | null>(null);
117→  const [statusFilter, setStatusFilter] = useState<RunStatusFilter>('all');
118→  const eventIdRef = useRef(0);
119→  const mountedRef = useRef(true);
120→
121→  /** Add an event log entry, capping at 500 entries */
122→  const addLogEntry = useCallback((
123→    source: EventLogEntry['source'],
124→    message: string,
125→    projectName?: string,
126→    runId?: number,
127→  ) => {
128→    setState(prev => ({
129→      ...prev,
130→      eventLog: [
131→        ...prev.eventLog.slice(-499),
132→        {
133→          id: String(++eventIdRef.current),
134→          timestamp: new Date().toISOString(),
135→          source,
136→          message,
137→          projectName,
138→          runId,
139→        },
140→      ],
141→    }));
142→  }, []);
143→
144→  // Load all projects and their active runs on mount
145→  useEffect(() => {
146→    mountedRef.current = true;
147→    let cancelled = false;
148→
149→    async function loadAll() {
150→      try {
151→        const projects = await api.listProjects();
152→        if (cancelled) return;
153→
154→        const issueMap = new Map<number, Issue>();
155→        const runMap = new Map<number, PipelineRun>();
156→        const phaseMap = new Map<number, PipelinePhase[]>();
157→
158→        for (const project of projects) {
159→          try {
160→            const board = await api.getBoard(project.id);
161→            if (cancelled) return;
162→            for (const col of board.columns) {
163→              for (const item of col.issues) {
164→                issueMap.set(item.issue.id, item.issue);
165→                if (item.active_run) {
166→                  runMap.set(item.active_run.id, item.active_run);
167→                }
168→              }
169→            }
170→          } catch {
171→            // Skip projects that fail to load
172→          }
173→        }
174→
175→        // Backfill agent teams and events for active runs
176→        const teamMap = new Map<number, AgentTeamDetail>();
177→        const eventMap = new Map<number, AgentEvent[]>();
178→        for (const [runId, run] of runMap) {
179→          if (cancelled) return;
180→          if (run.status !== 'running' && run.status !== 'queued') continue;
181→          try {
182→            const detail = await api.getRunTeam(runId);
183→            if (cancelled) return;
184→            if (detail) {
185→              teamMap.set(runId, detail);
186→              for (const task of detail.tasks) {
187→                try {
188→                  const events = await api.getTaskEvents(task.id, 200);
189→                  if (cancelled) return;
190→                  if (events.length > 0) eventMap.set(task.id, events);
191→                } catch { /* skip */ }
192→              }
193→            }
194→          } catch { /* no team for this run */ }
195→        }
196→
197→        if (!cancelled) {
198→          setState(prev => ({
199→            ...prev,
200→            projects,
201→            issues: issueMap,
202→            runs: runMap,
203→            phases: phaseMap,
204→            agentTeams: teamMap,
205→            agentEvents: eventMap,
206→            loading: false,
207→          }));
208→          addLogEntry('system', `Loaded ${projects.length} projects, ${runMap.size} active runs`);
209→        }
210→      } catch (err) {
211→        if (!cancelled) {
212→          setState(prev => ({
213→            ...prev,
214→            loading: false,
215→            error: err instanceof Error ? err.message : 'Failed to load',
216→          }));
217→        }
218→      }
219→    }
220→
221→    loadAll();
222→    return () => { cancelled = true; mountedRef.current = false; };
223→  }, [addLogEntry]);
224→
225→  // WebSocket message handler — uses a ref for issues to avoid stale closure
226→  const issuesRef = useRef(state.issues);
227→  issuesRef.current = state.issues;
228→
229→  useWsSubscribe(useCallback((msg: WsMessage) => {
230→    if (!mountedRef.current) return;
231→
232→    switch (msg.type) {
233→      case 'PipelineStarted': {
234→        const run = msg.data.run;
235→        setState(prev => {
236→          const newRuns = new Map(prev.runs);
237→          newRuns.set(run.id, run);
238→          return { ...prev, runs: newRuns };
239→        });
240→        const issue = issuesRef.current.get(run.issue_id);
241→        addLogEntry('system', `Pipeline started for "${issue?.title ?? `issue #${run.issue_id}`}"`, undefined, run.id);
242→        break;
243→      }
244→
245→      case 'PipelineProgress': {
246→        const { run_id, phase, iteration } = msg.data;
247→        setState(prev => {
248→          const newRuns = new Map(prev.runs);
249→          const existing = newRuns.get(run_id);
250→          if (existing) {
251→            newRuns.set(run_id, { ...existing, current_phase: phase, iteration });
252→          }
253→          return { ...prev, runs: newRuns };
254→        });
255→        break;
256→      }
257→
258→      case 'PipelineCompleted': {
259→        const run = msg.data.run;
260→        setState(prev => {
261→          const newRuns = new Map(prev.runs);
262→          newRuns.set(run.id, run);
263→          return { ...prev, runs: newRuns };
264→        });
265→        addLogEntry('system', 'Pipeline completed successfully', undefined, run.id);
266→        break;
267→      }
268→
269→      case 'PipelineFailed': {
270→        const run = msg.data.run;
271→        setState(prev => {
272→          const newRuns = new Map(prev.runs);
273→          newRuns.set(run.id, run);
274→          return { ...prev, runs: newRuns };
275→        });
276→        addLogEntry('error', `Pipeline failed: ${run.error ?? 'unknown error'}`, undefined, run.id);
277→        break;
278→      }
279→
280→      case 'PipelineOutput': {
281→        const { run_id, content } = msg.data;
282→        setState(prev => {
283→          const newEvents = new Map(prev.pipelineEvents);
284→          const existing = newEvents.get(run_id) ?? [];
285→          const event: AgentEvent = {
286→            id: existing.length + 1,
287→            task_id: 0,
288→            event_type: 'output',
289→            content,
290→            metadata: null,
291→            created_at: new Date().toISOString(),
292→          };
293→          newEvents.set(run_id, [...existing.slice(-199), event]);
294→          return { ...prev, pipelineEvents: newEvents };
295→        });
296→        break;
297→      }
298→
299→      case 'PipelinePhaseStarted': {
300→        const { run_id, phase_number, phase_name } = msg.data;
301→        setState(prev => {
302→          const newPhases = new Map(prev.phases);
303→          const existing = newPhases.get(run_id) ?? [];
304→          const newPhase: PipelinePhase = {
305→            id: 0,
306→            run_id,
307→            phase_number,
308→            phase_name,
309→            status: 'running',
310→            iteration: null,
311→            budget: null,
312→            started_at: new Date().toISOString(),
313→            completed_at: null,
314→            error: null,
315→          };
316→          newPhases.set(run_id, [...existing, newPhase]);
317→          return { ...prev, phases: newPhases };
318→        });
319→        addLogEntry('phase', `Phase "${phase_name}" started`, undefined, run_id);
320→        break;
321→      }
322→
323→      case 'PipelinePhaseCompleted': {
324→        const { run_id, phase_number, success } = msg.data;
325→        setState(prev => {
326→          const newPhases = new Map(prev.phases);
327→          const existing = newPhases.get(run_id) ?? [];
328→          newPhases.set(run_id, existing.map(p =>
329→            p.phase_number === phase_number
330→              ? { ...p, status: success ? 'completed' : 'failed', completed_at: new Date().toISOString() }
331→              : p
332→          ));
333→          return { ...prev, phases: newPhases };
334→        });
335→        addLogEntry('phase', `Phase completed (${success ? 'success' : 'failed'})`, undefined, run_id);
336→        break;
337→      }
338→
339→      case 'PipelineReviewStarted': {
340→        addLogEntry('review', 'Review started', undefined, msg.data.run_id);
341→        break;
342→      }
343→
344→      case 'PipelineReviewCompleted': {
345→        const { passed, findings_count } = msg.data;
346→        addLogEntry('review', `Review ${passed ? 'passed' : `failed (${findings_count} findings)`}`, undefined, msg.data.run_id);
347→        break;
348→      }
349→
350→      case 'PipelineBranchCreated': {
351→        const { run_id, branch_name } = msg.data;
352→        setState(prev => {
353→          const newRuns = new Map(prev.runs);
354→          const existing = newRuns.get(run_id);
355→          if (existing) {
356→            newRuns.set(run_id, { ...existing, branch_name });
357→          }
358→          return { ...prev, runs: newRuns };
359→        });
360→        addLogEntry('git', `Branch created: ${branch_name}`, undefined, run_id);
361→        break;
362→      }
363→
364→      case 'PipelinePrCreated': {
365→        const { run_id, pr_url } = msg.data;
366→        setState(prev => {
367→          const newRuns = new Map(prev.runs);
368→          const existing = newRuns.get(run_id);
369→          if (existing) {
370→            newRuns.set(run_id, { ...existing, pr_url });
371→          }
372→          return { ...prev, runs: newRuns };
373→        });
374→        addLogEntry('git', 'PR created', undefined, run_id);
375→        break;
376→      }
377→
378→      case 'TeamCreated': {
379→        const { run_id, team_id, strategy, isolation, plan_summary, tasks } = msg.data;
380→        setState(prev => {
381→          const newTeams = new Map(prev.agentTeams);
382→          newTeams.set(run_id, {
383→            team: { id: team_id, run_id, strategy, isolation, plan_summary, created_at: new Date().toISOString() },
384→            tasks: tasks ?? [],
385→          });
386→          return { ...prev, agentTeams: newTeams };
387→        });
388→        addLogEntry('agent', `Agent team created (${strategy})`, undefined, run_id);
389→        break;
390→      }
391→
392→      case 'AgentTaskStarted': {
393→        addLogEntry('agent', `Task "${msg.data.name}" started (${msg.data.role})`, undefined, undefined);
394→        break;
395→      }
396→
397→      case 'AgentThinking':
398→      case 'AgentAction':
399→      case 'AgentOutput':
400→      case 'AgentSignal': {
401→        const taskId = msg.data.task_id;
402→        setState(prev => {
403→          const newEvents = new Map(prev.agentEvents);
404→          const taskEvents = newEvents.get(taskId) ?? [];
405→          const event: AgentEvent = {
406→            id: taskEvents.length + 1,
407→            task_id: taskId,
408→            event_type: msg.type === 'AgentThinking' ? 'thinking'
409→              : msg.type === 'AgentAction' ? 'action'
410→              : msg.type === 'AgentOutput' ? 'output'
411→              : 'signal',
412→            content: msg.type === 'AgentAction' ? msg.data.summary : msg.data.content,
413→            metadata: msg.type === 'AgentAction' ? msg.data.metadata : null,
414→            created_at: new Date().toISOString(),
415→          };
416→          newEvents.set(taskId, [...taskEvents.slice(-199), event]);
417→          return { ...prev, agentEvents: newEvents };
418→        });
419→        break;
420→      }
421→
422→      case 'IssueCreated': {
423→        const issue = msg.data.issue;
424→        setState(prev => {
425→          const newIssues = new Map(prev.issues);
426→          newIssues.set(issue.id, issue);
427→          return { ...prev, issues: newIssues };
428→        });
429→        addLogEntry('system', `Issue created: "${issue.title}"`);
430→        break;
431→      }
432→
433→      case 'IssueDeleted': {
434→        setState(prev => {
435→          const newIssues = new Map(prev.issues);
436→          newIssues.delete(msg.data.issue_id);
437→          return { ...prev, issues: newIssues };
438→        });
439→        break;
440→      }
441→
442→      case 'ProjectCreated': {
443→        const project = msg.data.project;
444→        setState(prev => {
445→          if (prev.projects.some(p => p.id === project.id)) return prev;
446→          return { ...prev, projects: [...prev.projects, project] };
447→        });
448→        addLogEntry('system', `Project added: "${project.name}"`);
449→        break;
450→      }
451→
452→      case 'ProjectDeleted': {
453→        const deletedId = msg.data.project_id;
454→        setState(prev => {
455→          const newProjects = prev.projects.filter(p => p.id !== deletedId);
456→          const newIssues = new Map(prev.issues);
457→          const newRuns = new Map(prev.runs);
458→          // Remove issues belonging to the deleted project
459→          for (const [id, issue] of newIssues) {
460→            if (issue.project_id === deletedId) {
461→              // Also remove runs for this issue
462→              for (const [runId, run] of newRuns) {
463→                if (run.issue_id === id) newRuns.delete(runId);
464→              }
465→              newIssues.delete(id);
466→            }
467→          }
468→          return { ...prev, projects: newProjects, issues: newIssues, runs: newRuns };
469→        });
470→        addLogEntry('system', 'Project deleted');
471→        break;
472→      }
473→    }
474→  }, [addLogEntry]));
475→
476→  // Compute filtered and sorted agent run cards
477→  const agentRunCards: AgentRunCard[] = useMemo(() => {
478→    return Array.from(state.runs.values())
479→      .filter(run => {
480→        if (selectedProjectId !== null) {
481→          const issue = state.issues.get(run.issue_id);
482→          if (issue && issue.project_id !== selectedProjectId) return false;
483→        }
484→        if (statusFilter !== 'all' && run.status !== statusFilter) return false;
485→        return true;
486→      })
487→      .sort((a, b) => {
488→        const diff = (STATUS_ORDER[a.status] ?? 5) - (STATUS_ORDER[b.status] ?? 5);
489→        if (diff !== 0) return diff;
490→        return new Date(b.started_at).getTime() - new Date(a.started_at).getTime();
491→      })
492→      .map(run => ({
493→        run,
494→        issue: state.issues.get(run.issue_id) ?? {
495→          id: run.issue_id,
496→          project_id: 0,
497→          title: `Issue #${run.issue_id}`,
498→          description: '',
499→          column: 'backlog' as const,
500→          position: 0,
501→          priority: 'medium' as const,
502→          labels: [],
503→          github_issue_number: null,
504→          created_at: '',
505→          updated_at: '',
506→        },
507→        project: state.projects.find(p => {
508→          const issue = state.issues.get(run.issue_id);
509→          return issue && p.id === issue.project_id;
510→        }) ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
511→      }));
512→  }, [state.runs, state.issues, state.projects, selectedProjectId, statusFilter]);
513→
514→  // Compute idle issue cards — issues without any active pipeline run
515→  const idleIssueCards: IdleIssueCard[] = useMemo(() => {
516→    const issueIdsWithRuns = new Set(
517→      Array.from(state.runs.values()).map(r => r.issue_id)
518→    );
519→    return Array.from(state.issues.values())
520→      .filter(issue => {
521→        if (issueIdsWithRuns.has(issue.id)) return false;
522→        if (selectedProjectId !== null && issue.project_id !== selectedProjectId) return false;
523→        return true;
524→      })
525→      .map(issue => ({
526→        issue,
527→        project: state.projects.find(p => p.id === issue.project_id)
528→          ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
529→      }));
530→  }, [state.issues, state.runs, state.projects, selectedProjectId]);
531→
532→  // Compute status counts (unfiltered — always reflect total state)
533→  const statusCounts: Record<RunStatusFilter, number> = useMemo(() => {
534→    const runs = Array.from(state.runs.values());
535→    return {
536→      all: runs.length,
537→      running: runs.filter(r => r.status === 'running').length,
538→      queued: runs.filter(r => r.status === 'queued').length,
539→      completed: runs.filter(r => r.status === 'completed').length,
540→      failed: runs.filter(r => r.status === 'failed').length,
541→    };
542→  }, [state.runs]);
543→
544→  // Actions
545→  const triggerPipeline = useCallback(async (issueId: number) => {
546→    const run = await api.triggerPipeline(issueId);
547→    setState(prev => {
548→      const newRuns = new Map(prev.runs);
549→      newRuns.set(run.id, run);
550→      return { ...prev, runs: newRuns };
551→    });
552→  }, []);
553→
554→  const cancelPipeline = useCallback(async (runId: number) => {
555→    const run = await api.cancelPipelineRun(runId);
556→    setState(prev => {
557→      const newRuns = new Map(prev.runs);
558→      newRuns.set(run.id, run);
559→      return { ...prev, runs: newRuns };
560→    });
561→  }, []);
562→
563→  const createIssue = useCallback(async (projectId: number, title: string, description: string) => {
564→    const issue = await api.createIssue(projectId, title, description);
565→    setState(prev => {
566→      const newIssues = new Map(prev.issues);
567→      newIssues.set(issue.id, issue);
568→      return { ...prev, issues: newIssues };
569→    });
570→    return issue;
571→  }, []);
572→
573→  const createProject = useCallback(async (name: string, path: string) => {
574→    const project = await api.createProject(name, path);
575→    setState(prev => ({
576→      ...prev,
577→      projects: [...prev.projects, project],
578→    }));
579→    return project;
580→  }, []);
581→
582→  const cloneProject = useCallback(async (repoUrl: string) => {
583→    const project = await api.cloneProject(repoUrl);
584→    setState(prev => ({
585→      ...prev,
586→      projects: [...prev.projects, project],
587→    }));
588→    return project;
589→  }, []);
590→
591→  const deleteProject = useCallback(async (projectId: number) => {
592→    await api.deleteProject(projectId);
593→    // Optimistic removal — WS message will also trigger state cleanup
594→    setState(prev => ({
595→      ...prev,
596→      projects: prev.projects.filter(p => p.id !== projectId),
597→    }));
598→  }, []);
599→
600→  const refresh = useCallback(async () => {
601→    setState(prev => ({ ...prev, loading: true }));
602→    try {
603→      const projects = await api.listProjects();
604→      const issueMap = new Map<number, Issue>();
605→      const runMap = new Map<number, PipelineRun>();
606→      for (const project of projects) {
607→        try {
608→          const board = await api.getBoard(project.id);
609→          for (const col of board.columns) {
610→            for (const item of col.issues) {
611→              issueMap.set(item.issue.id, item.issue);
612→              if (item.active_run) {
613→                runMap.set(item.active_run.id, item.active_run);
614→              }
615→            }
616→          }
617→        } catch { /* skip */ }
618→      }
619→      setState(prev => ({
620→        ...prev,
621→        projects,
622→        issues: issueMap,
623→        runs: runMap,
624→        loading: false,
625→        error: null,
626→      }));
627→    } catch (err) {
628→      setState(prev => ({
629→        ...prev,
630→        loading: false,
631→        error: err instanceof Error ? err.message : 'Refresh failed',
632→      }));
633→    }
634→  }, []);
635→
636→  // Compute issue counts grouped by project ID
637→  const issuesByProject = useMemo(() => {
638→    const map = new Map<number, number>();
639→    for (const issue of state.issues.values()) {
640→      map.set(issue.project_id, (map.get(issue.project_id) ?? 0) + 1);
641→    }
642→    return map;
643→  }, [state.issues]);
644→
645→  return {
646→    projects: state.projects,
647→    agentRunCards,
648→    idleIssueCards,
649→    statusCounts,
650→    eventLog: state.eventLog,
651→    phases: state.phases,
652→    agentTeams: state.agentTeams,
653→    agentEvents: state.agentEvents,
654→    pipelineEvents: state.pipelineEvents,
655→    loading: state.loading,
656→    error: state.error,
657→    selectedProjectId,
658→    setSelectedProjectId,
659→    statusFilter,
660→    setStatusFilter,
661→    triggerPipeline,
662→    cancelPipeline,
663→    createIssue,
664→    createProject,
665→    cloneProject,
666→    deleteProject,
667→    refresh,
668→    issuesByProject,
669→  };
670→}
