  1→/** Expandable agent run card — collapsed summary with status, expanded tabbed detail view. */
  2→import { useState, useEffect, useRef } from 'react';
  3→import type { AgentRunCard as AgentRunCardType, PipelinePhase, AgentTeamDetail, AgentEvent, PipelineStatus, AgentEventType } from '../types';
  4→
  5→/** Tab options for the expanded detail view. */
  6→export type DetailTab = 'output' | 'phases' | 'files';
  7→
  8→/** Props for the AgentRunCard component. */
  9→export interface AgentRunCardProps {
 10→  /** Combined issue + run + project data for the card. */
 11→  card: AgentRunCardType;
 12→  /** Pipeline phases for the phases tab. */
 13→  phases?: PipelinePhase[];
 14→  /** Agent team detail with tasks. */
 15→  agentTeam?: AgentTeamDetail;
 16→  /** Agent events keyed by task ID. */
 17→  agentEvents?: Map<number, AgentEvent[]>;
 18→  /** Pipeline-level output events (for forge fallback path). */
 19→  pipelineEvents?: AgentEvent[];
 20→  /** Callback when the cancel button is clicked. */
 21→  onCancel?: (runId: number) => void;
 22→  /** Grid or list layout mode. */
 23→  viewMode: 'grid' | 'list';
 24→}
 25→
 26→/** Status dot color mapped to CSS custom properties. */
 27→export const STATUS_DOT_COLORS: Record<PipelineStatus, string> = {
 28→  running: 'var(--color-success)',
 29→  queued: 'var(--color-warning)',
 30→  completed: 'var(--color-success)',
 31→  failed: 'var(--color-error)',
 32→  cancelled: 'var(--color-text-secondary)',
 33→};
 34→
 35→/** Human-readable status labels. */
 36→export const STATUS_LABELS: Record<PipelineStatus, string> = {
 37→  running: 'RUNNING',
 38→  queued: 'QUEUED',
 39→  completed: 'DONE',
 40→  failed: 'FAILED',
 41→  cancelled: 'CANCELLED',
 42→};
 43→
 44→/** Color mapping for agent event types in the output tab. */
 45→const EVENT_TYPE_COLORS: Record<AgentEventType, string> = {
 46→  thinking: 'var(--color-text-secondary)',
 47→  action: '#39d353',
 48→  output: 'var(--color-success)',
 49→  signal: 'var(--color-warning)',
 50→  error: 'var(--color-error)',
 51→};
 52→
 53→/** AgentRunCard displays a pipeline run as a collapsible card with output, phases, and files tabs. */
 54→export default function AgentRunCard({
 55→  card,
 56→  phases,
 57→  agentTeam,
 58→  agentEvents,
 59→  pipelineEvents,
 60→  onCancel,
 61→  viewMode: _viewMode,
 62→}: AgentRunCardProps): React.JSX.Element {
 63→  const { run, issue, project } = card;
 64→  const [expanded, setExpanded] = useState(false);
 65→  const [activeTab, setActiveTab] = useState<DetailTab>('output');
 66→  const [elapsed, setElapsed] = useState('');
 67→  const outputRef = useRef<HTMLDivElement>(null);
 68→
 69→  // Live elapsed timer
 70→  useEffect(() => {
 71→    if (run.status !== 'running' && run.status !== 'queued') {
 72→      if (run.started_at && run.completed_at) {
 73→        const diff = new Date(run.completed_at).getTime() - new Date(run.started_at).getTime();
 74→        const m = Math.floor(diff / 60000);
 75→        const s = Math.floor((diff % 60000) / 1000);
 76→        setElapsed(`${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
 77→      }
 78→      return;
 79→    }
 80→
 81→    const start = new Date(run.started_at).getTime();
 82→    const tick = () => {
 83→      const diff = Date.now() - start;
 84→      const m = Math.floor(diff / 60000);
 85→      const s = Math.floor((diff % 60000) / 1000);
 86→      setElapsed(`${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`);
 87→    };
 88→    tick();
 89→    const interval = setInterval(tick, 1000);
 90→    return () => clearInterval(interval);
 91→  }, [run.status, run.started_at, run.completed_at]);
 92→
 93→  // Auto-scroll output
 94→  useEffect(() => {
 95→    if (expanded && activeTab === 'output' && outputRef.current) {
 96→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
 97→    }
 98→  });
 99→
100→  // Collect all events for this run — from agent team tasks and/or pipeline-level output
101→  const allEvents: AgentEvent[] = [];
102→  if (agentTeam && agentEvents) {
103→    for (const task of agentTeam.tasks) {
104→      const events = agentEvents.get(task.id) ?? [];
105→      allEvents.push(...events);
106→    }
107→  }
108→  if (pipelineEvents && pipelineEvents.length > 0) {
109→    allEvents.push(...pipelineEvents);
110→  }
111→  if (allEvents.length > 1) {
112→    allEvents.sort((a, b) => new Date(a.created_at).getTime() - new Date(b.created_at).getTime());
113→  }
114→
115→  const progress = run.phase_count
116→    ? Math.round(((run.current_phase ?? 0) / run.phase_count) * 100)
117→    : 0;
118→
119→  return (
120→    <div
121→      data-testid="agent-run-card"
122→      onClick={() => setExpanded(!expanded)}
123→      style={{
124→        backgroundColor: 'var(--color-bg-card)',
125→        border: '1px solid var(--color-border)',
126→        borderLeft: `3px solid ${STATUS_DOT_COLORS[run.status] ?? 'var(--color-border)'}`,
127→        cursor: 'pointer',
128→        transition: 'background-color 0.15s',
129→      }}
130→      onMouseEnter={e => (e.currentTarget.style.backgroundColor = 'var(--color-bg-card-hover)')}
131→      onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'var(--color-bg-card)')}
132→    >
133→      {/* Collapsed view */}
134→      <div style={{
135→        display: 'flex',
136→        alignItems: 'center',
137→        padding: '12px',
138→        gap: '12px',
139→      }}>
140→        {/* Status dot */}
141→        <span
142→          data-testid="status-dot"
143→          className={run.status === 'running' ? 'pulse-dot' : undefined}
144→          style={{
145→            width: '8px',
146→            height: '8px',
147→            borderRadius: '50%',
148→            backgroundColor: STATUS_DOT_COLORS[run.status],
149→            flexShrink: 0,
150→          }}
151→        />
152→
153→        {/* Project badge + title */}
154→        <div style={{ flex: 1, minWidth: 0 }}>
155→          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
156→            <span style={{
157→              fontSize: '10px',
158→              padding: '1px 6px',
159→              backgroundColor: 'var(--color-border)',
160→              color: 'var(--color-text-secondary)',
161→              textTransform: 'uppercase',
162→              letterSpacing: '0.5px',
163→              flexShrink: 0,
164→            }}>
165→              {project.name}
166→            </span>
167→            <span style={{
168→              overflow: 'hidden',
169→              textOverflow: 'ellipsis',
170→              whiteSpace: 'nowrap',
171→              fontSize: '13px',
172→            }}>
173→              {issue.title}
174→            </span>
175→          </div>
176→        </div>
177→
178→        {/* Phase dots */}
179→        {run.phase_count && (
180→          <div style={{ display: 'flex', gap: '3px', flexShrink: 0 }}>
181→            {Array.from({ length: run.phase_count }, (_, i) => {
182→              const phaseNum = i + 1;
183→              const isCurrent = phaseNum === (run.current_phase ?? 0);
184→              const isDone = phaseNum < (run.current_phase ?? 0);
185→              return (
186→                <span
187→                  key={i}
188→                  data-testid="phase-dot"
189→                  className={isCurrent && run.status === 'running' ? 'pulse-dot' : undefined}
190→                  style={{
191→                    width: '6px',
192→                    height: '6px',
193→                    borderRadius: '50%',
194→                    backgroundColor: isDone
195→                      ? 'var(--color-success)'
196→                      : isCurrent
197→                        ? 'var(--color-info)'
198→                        : 'var(--color-border)',
199→                  }}
200→                />
201→              );
202→            })}
203→          </div>
204→        )}
205→
206→        {/* Status label */}
207→        <span style={{
208→          fontSize: '11px',
209→          color: STATUS_DOT_COLORS[run.status],
210→          fontWeight: 600,
211→          flexShrink: 0,
212→          width: '60px',
213→          textAlign: 'right',
214→        }}>
215→          {STATUS_LABELS[run.status]}
216→        </span>
217→
218→        {/* Elapsed */}
219→        <span style={{
220→          fontSize: '12px',
221→          color: 'var(--color-text-secondary)',
222→          flexShrink: 0,
223→          width: '50px',
224→          textAlign: 'right',
