150→/// | GET    | `/api/projects/:id/board`       | Get Kanban board state    |
151→/// | POST   | `/api/projects/:id/sync-github` | Sync issues from GitHub   |
152→/// | POST   | `/api/projects/:id/issues`      | Create an issue           |
153→/// | GET    | `/api/issues/:id`               | Get issue detail          |
154→/// | PATCH  | `/api/issues/:id`               | Update issue title/body   |
155→/// | DELETE | `/api/issues/:id`               | Delete an issue           |
156→/// | PATCH  | `/api/issues/:id/move`          | Move to column/position   |
157→/// | POST   | `/api/issues/:id/run`           | Trigger pipeline          |
158→/// | GET    | `/api/runs/:id`                 | Get pipeline run status   |
159→/// | POST   | `/api/runs/:id/cancel`          | Cancel a running pipeline |
160→/// | GET    | `/api/runs/:id/team`            | Get agent team for run    |
161→/// | GET    | `/api/tasks/:id/events`         | Get agent task events     |
162→/// | GET    | `/api/github/status`            | GitHub OAuth status       |
163→/// | POST   | `/api/github/device-code`       | Initiate device flow      |
164→/// | POST   | `/api/github/poll`              | Poll device code status   |
165→/// | POST   | `/api/github/connect`           | Connect with PAT token    |
166→/// | GET    | `/api/github/repos`             | List user's GitHub repos  |
167→/// | POST   | `/api/github/disconnect`        | Remove GitHub token       |
168→/// | GET    | `/health`                       | Liveness probe            |
169→pub fn api_router() -> Router<SharedState> {
170→    Router::new()
171→        .route("/api/projects", get(list_projects).post(create_project))
172→        .route("/api/projects/clone", post(clone_project))
173→        .route(
174→            "/api/projects/{id}",
175→            get(get_project).delete(delete_project),
176→        )
177→        .route("/api/projects/{id}/board", get(get_board))
178→        .route("/api/projects/{id}/sync-github", post(sync_github_issues))
179→        .route("/api/projects/{id}/issues", post(create_issue))
180→        .route(
181→            "/api/issues/{id}",
182→            get(get_issue).patch(update_issue).delete(delete_issue),
183→        )
184→        .route("/api/issues/{id}/move", patch(move_issue))
185→        .route("/api/issues/{id}/run", post(trigger_pipeline))
186→        .route("/api/runs/{id}", get(get_pipeline_run))
187→        .route("/api/runs/{id}/cancel", post(cancel_pipeline_run))
188→        .route("/api/runs/{id}/team", get(get_run_team))
189→        .route("/api/tasks/{id}/events", get(get_task_events))
190→        .route("/api/github/status", get(github_status))
191→        .route("/api/github/device-code", post(github_device_code))
192→        .route("/api/github/poll", post(github_poll_token))
193→        .route("/api/github/connect", post(github_connect_token))
194→        .route("/api/github/repos", get(github_list_repos))
195→        .route("/api/github/disconnect", post(github_disconnect))
196→        .route("/api/screenshots/{*path}", get(serve_screenshot))
197→        .route("/health", get(health_check))
198→}
