200→// ── Helpers ───────────────────────────────────────────────────────────
201→
202→/// Extract "owner/repo" from various GitHub URL formats.
203→fn parse_github_owner_repo(url: &str) -> Option<String> {
204→    let url = url.trim().trim_end_matches('/').trim_end_matches(".git");
205→    // Handle https://github.com/owner/repo and https://TOKEN@github.com/owner/repo
