            })
            .await
            .map_err(|e| {
                let msg = e.to_string();
                if msg.contains("not found") {
                    ApiError::from(FactoryError::ProjectNotFound { id: project_id })
                } else {
                    ApiError::Internal(msg)
                }
            })?;

