You are the backend developer. Implement Steps 1-5 of the Factory UI improvements plan in Rust. Work through each step sequentially, writing tests first then implementation.

## Step 1: FileAction enum in models.rs

Add to `src/factory/models.rs` (before the `#[cfg(test)]` block):
```rust
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum FileAction {
    Created,
    Modified,
    Deleted,
}
```

Add test `test_file_action_serde` to the existing `#[cfg(test)] mod tests` block — verify Created/Modified/Deleted serialize to snake_case and roundtrip.

## Step 2: New WS message variants in ws.rs

Add two new variants to the `WsMessage` enum in `src/factory/ws.rs` (after the `PipelineOutput` variant at around line 168):
```rust
PipelineOutputEvent {
    run_id: i64,
    content_type: String,
    content: String,
    tool_id: Option<String>,
    input_summary: Option<String>,
},
PipelineFileChanged {
    run_id: i64,
    file_path: String,
    action: FileAction,
},
```

Note: `FileAction` is in `super::models::*` which is already imported via `use super::models::*;`

Add tests to the existing `#[cfg(test)] mod tests` in ws.rs:
- `test_ws_pipeline_output_event_serde` — roundtrip serialization
- `test_ws_pipeline_file_changed_serde` — roundtrip serialization

## Step 3: Stream-JSON parser in pipeline.rs

Add three pure functions and a helper enum to `src/factory/pipeline.rs`. Add them BEFORE the `execute_pipeline_streaming` function (around line 1247). The enum should use Serialize:

```rust
use serde::Serialize;

#[derive(Debug, Clone, PartialEq, Serialize)]
#[serde(tag = "content_type")]
enum StreamJsonEvent {
    Text { text: String },
    ToolStart { tool_name: String, tool_id: String, input_summary: String },
    ToolEnd { tool_id: String, output_preview: String },
    Thinking { text: String },
    Skip,
}

fn parse_stream_json_line(line: &str) -> StreamJsonEvent {
    // Try to parse as JSON
    let json: serde_json::Value = match serde_json::from_str(line) {
        Ok(v) => v,
        Err(_) => {
            // Not JSON — treat as plain text
            return StreamJsonEvent::Text { text: line.to_string() };
        }
    };

    // Skip metadata-only messages
    let msg_type = json.get("type").and_then(|t| t.as_str()).unwrap_or("");
    match msg_type {
        "message_start" | "message_stop" | "message_delta" | "content_block_stop" | "result" => {
            return StreamJsonEvent::Skip;
        }
        _ => {}
    }

    // content_block_delta with text_delta → Text
    if msg_type == "content_block_delta" {
        if let Some(delta) = json.get("delta") {
            if delta.get("type").and_then(|t| t.as_str()) == Some("text_delta") {
                if let Some(text) = delta.get("text").and_then(|t| t.as_str()) {
                    return StreamJsonEvent::Text { text: text.to_string() };
                }
            }
            if delta.get("type").and_then(|t| t.as_str()) == Some("thinking_delta") {
                if let Some(text) = delta.get("thinking").and_then(|t| t.as_str()) {
                    return StreamJsonEvent::Thinking { text: text.to_string() };
                }
            }
        }
    }

    // content_block_start with tool_use → ToolStart
    if msg_type == "content_block_start" {
        if let Some(cb) = json.get("content_block") {
            if cb.get("type").and_then(|t| t.as_str()) == Some("tool_use") {
                let tool_name = cb.get("name").and_then(|n| n.as_str()).unwrap_or("unknown").to_string();
                let tool_id = cb.get("id").and_then(|i| i.as_str()).unwrap_or("").to_string();
                let input_summary = extract_tool_input_summary(&tool_name, cb.get("input"));
                return StreamJsonEvent::ToolStart { tool_name, tool_id, input_summary };
            }
        }
    }

    // Legacy format: subtype == "tool_use"
    if json.get("subtype").and_then(|s| s.as_str()) == Some("tool_use") {
        let tool_name = json.get("tool_name").and_then(|n| n.as_str()).unwrap_or("unknown").to_string();
        let tool_id = json.get("tool_use_id").and_then(|i| i.as_str()).unwrap_or("").to_string();
        let input_summary = extract_tool_input_summary(&tool_name, json.get("input"));
        return StreamJsonEvent::ToolStart { tool_name, tool_id, input_summary };
    }

    // Full assistant message with content array containing tool_use
    if json.get("role").and_then(|r| r.as_str()) == Some("assistant") {
        if let Some(content) = json.get("content").and_then(|c| c.as_array()) {
            for block in content {
                if block.get("type").and_then(|t| t.as_str()) == Some("tool_use") {
                    let tool_name = block.get("name").and_then(|n| n.as_str()).unwrap_or("unknown").to_string();
                    let tool_id = block.get("id").and_then(|i| i.as_str()).unwrap_or("").to_string();
                    let input_summary = extract_tool_input_summary(&tool_name, block.get("input"));
                    return StreamJsonEvent::ToolStart { tool_name, tool_id, input_summary };
                }
            }
        }
    }

    StreamJsonEvent::Skip
}

fn extract_tool_input_summary(tool_name: &str, input: Option<&serde_json::Value>) -> String {
    let input = match input {
        Some(v) => v,
        None => return String::new(),
    };

    match tool_name {
        "Read" | "read" | "file_read" => {
            input.get("file_path")
                .and_then(|p| p.as_str())
                .unwrap_or("")
                .to_string()
        }
        "Write" | "write" | "file_write" => {
            input.get("file_path")
                .and_then(|p| p.as_str())
                .unwrap_or("")
                .to_string()
        }
        "Edit" | "edit" | "file_edit" => {
            input.get("file_path")
                .and_then(|p| p.as_str())
                .unwrap_or("")
                .to_string()
        }
        "Bash" | "bash" | "execute_command" => {
            let cmd = input.get("command")
                .and_then(|c| c.as_str())
                .unwrap_or("");
            if cmd.len() > 80 {
                format!("{}...", &cmd[..80])
            } else {
                cmd.to_string()
            }
        }
        _ => String::new(),
    }
}

fn extract_file_change(tool_name: &str, input: Option<&serde_json::Value>) -> Option<(String, FileAction)> {
    let input = input?;

    match tool_name {
        "Write" | "write" | "file_write" => {
            let path = input.get("file_path").and_then(|p| p.as_str())?;
            Some((path.to_string(), FileAction::Created))
        }
        "Edit" | "edit" | "file_edit" => {
            let path = input.get("file_path").and_then(|p| p.as_str())?;
            Some((path.to_string(), FileAction::Modified))
        }
        _ => None,
    }
}
```

